/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const n = nums.length;
    const adj = Array(n).fill(0).map(() => []);

    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;

    // Iterate through all non-empty subsets using bitmasks
    // The mask represents the subset s. If the i-th bit is set, node i is in s.
    for (let mask = 1; mask < (1 << n); mask++) {
        // 1. Calculate the sum of values for nodes in s
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        // Check if the sum is even
        if (sum % 2 !== 0) {
            continue;
        }

        // 2. Check if the induced subgraph is connected

        // Find the first node in the subset s to start BFS/DFS from
        let startNode = -1;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                startNode = i;
                break;
            }
        }

        if (startNode === -1) {
            // This should not happen as mask >= 1
            continue;
        }

        // Use BFS to check connectivity within the induced subgraph
        const visited = new Array(n).fill(false);
        const queue = [startNode];
        visited[startNode] = true;
        let visitedCount = 1;

        while (queue.length > 0) {
            const u = queue.shift();

            for (const v of adj[u]) {
                // Check if v is in the subset s AND v has not been visited
                if (((mask >> v) & 1) && !visited[v]) {
                    visited[v] = true;
                    visitedCount++;
                    queue.push(v);
                }
            }
        }

        // The subgraph is connected if the number of reachable nodes 
        // (that belong to s) equals the total number of nodes in s.
        let subsetSize = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subsetSize++;
            }
        }

        if (visitedCount === subsetSize) {
            // Both conditions met: connected and even sum
            count++;
        }
    }

    return count;
}

